 function addLogo(doc) {
    try {
        // Replace with your actual base64-encoded logo
        const logoBase64 = 'data:image/jpeg;base64,';
        doc.addImage(logoBase64, 'JPEG', 10, 10, 30, 15);
        // Add RC number below logo
        doc.setFontSize(8);
        doc.setTextColor(100, 100, 100);
        doc.text('RC: 9384125', 10, 28);
        doc.setTextColor(0);
    } catch (e) {
        // Fallback: draw a gray rectangle and RC text
        doc.setFillColor(200, 200, 200);
        doc.rect(10, 10, 30, 15, 'F');
        doc.setTextColor(100, 100, 100);
        doc.setFontSize(8);
        doc.text('LOGO', 20, 20);
        doc.text('RC: 9384125', 10, 28);
        doc.setTextColor(0);
    }
}

// Helper to add signature at the bottom of the current page, or on a new page if needed
function addSignature(doc, currentY) {
    const pageHeight = doc.internal.pageSize.height;
    const marginBottom = 30;
    const signatureY = pageHeight - marginBottom;

    // If there's not enough space for the signature lines (approx 20 units), add a new page
    if (currentY > signatureY - 20) {
        doc.addPage();
        // Reset position on new page
        currentY = 30;
        // Redraw logo and RC on new page
        addLogo(doc);
    }

    // Place signature at bottom margin
    doc.line(20, signatureY, 80, signatureY);
    doc.line(130, signatureY, 190, signatureY);
    doc.text('Chairman', 40, signatureY + 6);
    doc.text('Secretary', 150, signatureY + 6);
}

function generateClientPDF(loan) {
    try {
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF();

        addLogo(doc);

        doc.setFontSize(18);
        doc.setTextColor(0, 51, 102);
        doc.text('TRUSTED FRIENDS VENTURES LIMITED', 105, 20, { align: 'center' });
        doc.setFontSize(10);
        doc.setTextColor(80, 80, 80);
        doc.text('Reliable Loan Management & Financial Services', 105, 28, { align: 'center' });

        doc.setFillColor(0, 102, 204);
        doc.rect(0, 37, 212, 27, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(20);
        doc.text('LOAN STATEMENT', 105, 52, { align: 'center' });
        doc.setFontSize(10);
        doc.text(`Generated: ${new Date().toLocaleString()}`, 105, 62, { align: 'center' });

        doc.setTextColor(0);
        doc.setFontSize(14);
        doc.text(`Client: ${loan.names}`, 14, 80);
        doc.setFontSize(11);
        const dateStr = loan.date ? new Date(loan.date.seconds * 1000).toLocaleDateString() : '—';
        doc.text(`Disbursement Date: ${dateStr}`, 14, 90);

        doc.setFillColor(240, 248, 255);
        doc.rect(14, 100, 180, 50, 'F');
        doc.setFontSize(12);
        doc.text(`Principal Amount: NGN ${loan.amount.toLocaleString()}`, 20, 110);
        doc.text(`Total Interest: NGN ${loan.interest.toLocaleString()}`, 20, 118);
        doc.text(`Penalty Accumulated: NGN ${loan.penalty_charged.toLocaleString()}`, 20, 126);
        doc.text(`Grand Total Due: NGN ${loan.g_total.toLocaleString()}`, 20, 134);
        doc.setTextColor(220, 53, 69);
        doc.setFontSize(14);
        doc.text(`Outstanding Balance: NGN ${loan.balance.toLocaleString()}`, 20, 146);

        doc.setTextColor(0);
        if (typeof doc.autoTable === 'function') {
            doc.autoTable({
                startY: 160,
                head: [['SN', 'Date', 'Int. Rate', 'Duration', 'Admin Fee', 'Remitted', 'Balance']],
                body: [[
                    loan.sn,
                    dateStr,
                    loan.int_rate + '%',
                    loan.duration,
                    'NGN ' + loan.admin_fees.toLocaleString(),
                    'NGN ' + loan.amt_remitted.toLocaleString(),
                    'NGN ' + loan.balance.toLocaleString()
                ]],
                theme: 'striped',
                headStyles: { fillColor: [0, 102, 204] }
            });
        } else {
            doc.text('Table could not be generated (autoTable missing)', 20, 170);
        }

        // Add signature at bottom
        const lastY = doc.lastAutoTable?.finalY || 180;
        addSignature(doc, lastY);

        doc.save(`loan_${loan.sn}.pdf`);
        showToast('PDF generated successfully');
    } catch (error) {
        console.error('PDF generation error:', error);
        showToast('Failed to generate PDF: ' + error.message, 'error');
    }
}

function generateProfitLossPDF(data, periodText) {
    try {
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF();

        addLogo(doc);

        doc.setFontSize(18);
        doc.setTextColor(0, 51, 102);
        doc.text('TRUSTED FRIENDS VENTURES LIMITED', 105, 20, { align: 'center' });
        doc.setFillColor(0, 102, 204);
        doc.rect(0, 40, 210, 30, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(20);
        doc.text('INCOME STATEMENT', 105, 60, { align: 'center' });
        doc.setFontSize(11);
        doc.text(`Period: ${periodText}`, 105, 70, { align: 'center' });
        doc.text(`Generated: ${new Date().toLocaleString()}`, 105, 78, { align: 'center' });

        doc.setTextColor(0);
        let y = 90;
        doc.setFontSize(14);
        doc.text('INCOME (Revenue)', 14, y);
        y += 8;

        const incomeRows = [
            ['Interest Income', `NGN ${(data.revenue?.interest || 0).toLocaleString()}`],
            ['Admin / Processing Fees', `NGN ${(data.revenue?.adminFees || 0).toLocaleString()}`],
            ['Penalty Income', `NGN ${(data.revenue?.penalty || 0).toLocaleString()}`]
        ];
        for (let [cat, amt] of Object.entries(data.otherIncome || {})) {
            incomeRows.push([cat, `NGN ${amt.toLocaleString()}`]);
        }
        incomeRows.push(['TOTAL REVENUE', `NGN ${(data.totalRevenue || 0).toLocaleString()}`]);

        if (typeof doc.autoTable === 'function') {
            doc.autoTable({
                startY: y,
                body: incomeRows,
                theme: 'plain',
                styles: { fontSize: 11 },
                columnStyles: { 0: { cellWidth: 140 }, 1: { cellWidth: 50, halign: 'right' } }
            });

            y = doc.lastAutoTable.finalY + 10;
            doc.setFontSize(14);
            doc.text('OPERATING EXPENSES', 14, y);
            y += 8;

            const expenseRows = [];
            for (let [cat, amt] of Object.entries(data.expenses || {})) {
                expenseRows.push([cat, `NGN ${amt.toLocaleString()}`]);
            }
            expenseRows.push(['TOTAL EXPENSES', `NGN ${(data.totalExpenses || 0).toLocaleString()}`]);

            doc.autoTable({
                startY: y,
                body: expenseRows,
                theme: 'plain',
                styles: { fontSize: 11 },
                columnStyles: { 0: { cellWidth: 140 }, 1: { cellWidth: 50, halign: 'right' } }
            });

            y = doc.lastAutoTable.finalY + 15;
            doc.setFontSize(14);
            doc.text(`Net Operating Profit / (Loss): NGN ${(data.netOperating || 0).toLocaleString()}`, 14, y);
            y += 10;
            
            doc.setFontSize(12);
            doc.text("Owner's Equity (Net):", 14, y);
            y += 6;
            
            const equityRows = [];
            for (let [owner, amt] of Object.entries(data.equityPerOwner || {})) {
                equityRows.push([owner, `NGN ${amt.toLocaleString()}`]);
            }
            if (equityRows.length > 0) {
                doc.autoTable({
                    startY: y,
                    body: equityRows,
                    theme: 'plain',
                    styles: { fontSize: 10 },
                    columnStyles: { 0: { cellWidth: 140 }, 1: { cellWidth: 50, halign: 'right' } }
                });
                y = doc.lastAutoTable.finalY + 5;
            } else {
                doc.text('None', 14, y);
                y += 10;
            }
            
            doc.setFontSize(14);
            doc.text(`Total Net Equity: NGN ${(data.totalEquity || 0).toLocaleString()}`, 14, y);
            y += 10;
            
            doc.setFontSize(16);
            if (data.finalPosition >= 0) {
                doc.setTextColor(0, 128, 0);
            } else {
                doc.setTextColor(220, 53, 69);
            }
            doc.text(`Final Net Position: NGN ${(data.finalPosition || 0).toLocaleString()}`, 14, y);
        } else {
            doc.text('Tables could not be generated (autoTable missing)', 20, y);
        }

        const lastY = doc.lastAutoTable?.finalY || y;
        addSignature(doc, lastY);

        doc.save(`profit_loss_${periodText.replace(/\s/g, '_').replace(/[^a-zA-Z0-9_]/g, '')}.pdf`);
        showToast('PDF generated successfully');
    } catch (error) {
        console.error('P&L PDF generation error:', error);
        showToast('Failed to generate P&L PDF: ' + error.message, 'error');
    }
}

function generateOwnerEquityPDF(owner, transactions, netTotal) {
    try {
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF();

        addLogo(doc);

        doc.setFontSize(18);
        doc.setTextColor(0, 51, 102);
        doc.text('TRUSTED FRIENDS VENTURES LIMITED', 105, 20, { align: 'center' });

        doc.setFillColor(0, 102, 204);
        doc.rect(0, 35, 210, 25, 'F');
        doc.setTextColor(255, 255, 255);
        doc.setFontSize(20);
        doc.text('EQUITY STATEMENT', 105, 52, { align: 'center' });

        doc.setTextColor(0);
        doc.setFontSize(11);
        doc.text(`Owner: ${owner}`, 105, 65, { align: 'center' });
        doc.text(`Generated: ${new Date().toLocaleString()}`, 105, 72, { align: 'center' });

        let y = 85;
        doc.setFontSize(12);
        doc.text('Transaction History', 14, y);
        y += 8;

        const tableData = transactions.map(t => [
            t.date ? new Date(t.date.seconds * 1000).toLocaleDateString() : '',
            t.type,
            'NGN ' + t.amount.toLocaleString(),
            t.description || ''
        ]);

        if (typeof doc.autoTable === 'function') {
            doc.autoTable({
                startY: y,
                head: [['Date', 'Type', 'Amount', 'Description']],
                body: tableData,
                theme: 'striped',
                headStyles: { fillColor: [0, 102, 204] }
            });

            y = doc.lastAutoTable.finalY + 10;
            doc.setFontSize(14);
            doc.text(`Net Total: NGN ${netTotal.toLocaleString()}`, 14, y);
        } else {
            doc.text('Table could not be generated (autoTable missing)', 20, y);
        }

        const lastY = doc.lastAutoTable?.finalY || y;
        addSignature(doc, lastY);

        doc.save(`equity_${owner.replace(/\s/g, '_')}.pdf`);
        showToast('PDF generated successfully');
    } catch (error) {
        console.error('PDF generation error:', error);
        showToast('Failed to generate PDF: ' + error.message, 'error');
    }
}

function downloadCSV(data, filename) {
    try {
        const csv = Papa.unparse(data);
        const blob = new Blob([csv], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        a.click();
        URL.revokeObjectURL(url);
        showToast('CSV downloaded successfully');
    } catch (error) {
        console.error('CSV download error:', error);
        showToast('Failed to download CSV: ' + error.message, 'error');
    }
}

window.generateClientPDF = generateClientPDF;
window.generateProfitLossPDF = generateProfitLossPDF;
window.generateOwnerEquityPDF = generateOwnerEquityPDF;
window.downloadCSV = downloadCSV;